sql:
SELECT COUNT(object_id) 
FROM astronomical_objects 
WHERE year = 2022;

SELECT name 
FROM astronomical_objects 
WHERE mass = (SELECT MAX(mass) FROM astronomical_objects);

SELECT name, mass 
FROM astronomical_objects
WHERE mass > 10000000;

SELECT name
FROM astronomical_objects
WHERE year = 2020 AND mass BETWEEN 10 AND 50;

SELECT object_id, name, POWER(mass, 2) AS mass_squared
FROM astronomical_objects
ORDER BY mass ASC;

external_knowledge:
- Celestial giant refers to the object with the highest mass; 
- The earliest recorded sighting is the first observation date; 
- The classification refers to the class_name of the first observed object; 
- The discovery method refers to the method_name used to discover the first observed object.

sql:
SELECT ao.name, ao.year, u.user_name
FROM astronomical_objects ao
JOIN users u ON ao.created_by = u.user_id;
